# Process all batches
with open('nursepass_1100.html', 'r', encoding='utf-8') as f:
    content = f.read()
start = content.index('const QUESTIONS = [')
start = content.index('[', start)
depth = 0
for i, c in enumerate(content[start:], start):
    if c == '[': depth += 1
    elif c == ']':
        depth -= 1
        if depth == 0: end = i; break
existing = json.loads(content[start:end+1])

for batch in BATCHES:
    START_ID = batch["start_id"]
    FIELD = batch["field"]
    SEED = batch["seed"]
    RAW = batch["questions"]

    TARGET = ['A']*13 + ['B']*12 + ['C']*13 + ['D']*12
    random.seed(SEED)
    random.shuffle(TARGET)

    NEW_QUESTIONS = []
    for idx, (question, correct, w1, w2, w3, explanation, stars) in enumerate(RAW):
        qid = START_ID + idx
        target_answer = TARGET[idx]
        choices_list = [w1, w2, w3]
        random.shuffle(choices_list)
        all_choices = {}
        positions = [p for p in ['A','B','C','D'] if p != target_answer]
        all_choices[target_answer] = correct
        for i, pos in enumerate(positions):
            all_choices[pos] = choices_list[i]
        NEW_QUESTIONS.append({
            "id": qid, "category": "一般", "field": FIELD,
            "question": question, "choices": all_choices,
            "answer": target_answer, "explanation": explanation, "stars": stars
        })

    dist = {k: sum(1 for q in NEW_QUESTIONS if q['answer']==k) for k in 'ABCD'}
    end_id = START_ID + len(RAW) - 1
    existing = [q for q in existing if not (START_ID <= q['id'] <= end_id)]
    existing = existing + NEW_QUESTIONS
    print(f"✅ {FIELD}: ID {START_ID}〜{end_id}, A:{dist['A']} B:{dist['B']} C:{dist['C']} D:{dist['D']}")

all_questions = existing
new_json = json.dumps(all_questions, ensure_ascii=False, separators=(',', ':'))
start_pos = content.index('const QUESTIONS = [')
start_pos = content.index('[', start_pos)
depth = 0
for i, c in enumerate(content[start_pos:], start_pos):
    if c == '[': depth += 1
    elif c == ']':
        depth -= 1
        if depth == 0: end_pos = i; break
new_content = content[:start_pos] + new_json + content[end_pos+1:]
with open('nursepass_1100.html', 'w', encoding='utf-8') as f:
    f.write(new_content)
print(f"✅ バッチ11-12完了: 合計 {len(all_questions)} 問")
